                     Interfaces.NRF52.UICR.Enabled;
   CPUFPBEN       : DEBUGCTRL_CPUFPBEN_Field :=
                     Interfaces.NRF52.UICR.Enabled;
   Reserved_16_31 : Interfaces.NRF52.UInt16 := 16#FFFF#;
end record;

type NFCPINS_Register is record
   PROTECT       : NFCPINS_PROTECT_Field := Interfaces.NRF52.UICR.Nfc;
