   UNUSED3   : aliased Interfaces.NRF52.UInt32;
   NRFFW     : aliased NRFFW_Registers;
   NRFHW     : aliased NRFHW_Registers;
   CUSTOMER  : aliased CUSTOMER_Registers;
   PSELRESET : aliased PSELRESET_Registers;
